import sys

class Solution:
    def countSetBits(self, n: int) -> int:
        def count_set_bits_in_num(num: int) -> int:
            count = 0
            while num:
                count += num & 1
                num >>= 1
            return count

        total_count = 0
        for i in range(1, n + 1):
            total_count += count_set_bits_in_num(i)
        return total_count

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.countSetBits(n)
    print(ans)

solutions.cpp:
#include <numeric>

#include <iostream>

class Solution {
public:
    int countSetBits(int n) {
        int total_count = 0;
        for (int i = 1; i <= n; i++) {
            int count = 0;
            int num = i;
            while (num) {
                count += num & 1;
                num >>= 1;
            }
            total_count += count;
        }
        return total_count;
    }
};

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);
    int n;
    if (!(std::cin >> n)) return 0;
    Solution sol;
    int ans = sol.countSetBits(n);
    std::cout << ans << std::endl;
    return 0;
}
